+/// Batched weighted addition for speculative decoding
+/// Processes multiple tokens in parallel: expert_out[batch, n_embd] → accum[batch, n_embd]
+/// Each token has its own weight from weights[batch, n_expert]
+kernel void moe_expert_weighted_add_from_buffer_batched(
+    device const float *expert_out [[buffer(0)]],       // [batch_size, n_embd] - expert outputs
+    device float *accum [[buffer(1)]],                  // [batch_size, n_embd] - accumulator
+    device const float *weights [[buffer(2)]],          // [batch_size, n_expert] - per-token softmax weights
+    constant uint &expert_idx [[buffer(3)]],            // which expert's weight to use
+    constant uint &n_embd [[buffer(4)]],
+    constant uint &n_expert [[buffer(5)]],              // number of experts (8 for Mixtral)
+    uint2 idx [[thread_position_in_grid]]               // (embd_idx, batch_idx)
+) {
+    const uint embd_idx = idx.x;
+    const uint batch_idx = idx.y;
+
+    if (embd_idx >= n_embd) return;
+
+    // Each token in the batch has its own weight
+    // weights layout: [batch_size, n_expert] row-major
+    const float weight = weights[batch_idx * n_expert + expert_idx];
+
+    // expert_out and accum layout: [batch_size, n_embd] row-major
+    const uint offset = batch_idx * n_embd + embd_idx;
+    accum[offset] += weight * expert_out[offset];
+}
