+/// OPTIMIZED v2: Full SIMD utilization (32 threads = 16 blocks × 2 threads/block)
+/// Each thread handles TWO chunks (128 values) instead of whole block (256 values)
+kernel void moe_expert_ffn_q4_k_v2(
+    device const float *x [[buffer(0)]],
+    device const uchar *gate_q4 [[buffer(1)]],
+    device const uchar *up_q4 [[buffer(2)]],
+    device const uchar *down_q4 [[buffer(3)]],
+    device float *gate_buf [[buffer(4)]],
+    device float *up_buf [[buffer(5)]],
+    device float *out [[buffer(6)]],
+    constant uint &batch_size [[buffer(7)]],
+    constant uint &n_embd [[buffer(8)]],
+    constant uint &n_ff [[buffer(9)]],
+    constant uint &batch_offset [[buffer(10)]],
+    constant uint *token_indices [[buffer(11)]],
+    uint3 tgpig [[threadgroup_position_in_grid]],
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    const int local_idx = tgpig.x;
+    const int row_idx = tgpig.y;
+
+    if (local_idx >= batch_size || row_idx >= n_ff) return;
+
+    const int actual_token_idx = (token_indices != nullptr) ? token_indices[local_idx] : (local_idx + batch_offset);
+    const int batch_idx = actual_token_idx;
+
+    // Q4_K: 144 bytes per 256 values, 16 blocks for n_embd=4096
+    const int blocks_per_row = (n_embd + 255) / 256;
+    const int row_stride_bytes = blocks_per_row * 144;
+
+    device const block_q4_K *gate_row = (device const block_q4_K *)(gate_q4 + row_idx * row_stride_bytes);
+    device const block_q4_K *up_row = (device const block_q4_K *)(up_q4 + row_idx * row_stride_bytes);
+
+    float gate_sum = 0.0f;
+    float up_sum = 0.0f;
+    const int batch_input_offset = batch_idx * n_embd;
+
+    // v2: 32 threads process 16 blocks (2 threads per block)
+    // Thread tiisg processes: block = tiisg/2, half_idx = tiisg % 2
+    // half_idx 0: chunks 0,1 (values 0-127), half_idx 1: chunks 2,3 (values 128-255)
+    const int block_idx = tiisg / 2;
+    const int half_idx = tiisg & 1;
+
+    if (block_idx < blocks_per_row) {
+        device const block_q4_K *gb = gate_row + block_idx;
+        device const block_q4_K *ub = up_row + block_idx;
+
+        const float gd = (float)gb->d;
+        const float gdmin = (float)gb->dmin;
+        const float ud = (float)ub->d;
+        const float udmin = (float)ub->dmin;
+
+        const int input_base = batch_input_offset + block_idx * 256 + half_idx * 128;
+
+        // Process 2 chunks (128 values) - half_idx 0 does chunks 0,1; half_idx 1 does chunks 2,3
+        for (int chunk_offset = 0; chunk_offset < 2; chunk_offset++) {
+            const int chunk = half_idx * 2 + chunk_offset;
+            const int is = chunk * 2;
+            const int qs_base = chunk * 32;
+            const int x_base = input_base + chunk_offset * 64;
+
+            float gd1, gm1, ud1, um1;
+            if (is < 4) {
+                gd1 = gd * (float)(gb->scales[is] & 63);
+                gm1 = gdmin * (float)(gb->scales[is + 4] & 63);
+                ud1 = ud * (float)(ub->scales[is] & 63);
+                um1 = udmin * (float)(ub->scales[is + 4] & 63);
+            } else {
+                gd1 = gd * (float)((gb->scales[is + 4] & 0x0F) | ((gb->scales[is - 4] >> 6) << 4));
+                gm1 = gdmin * (float)((gb->scales[is + 4] >> 4) | ((gb->scales[is] >> 6) << 4));
+                ud1 = ud * (float)((ub->scales[is + 4] & 0x0F) | ((ub->scales[is - 4] >> 6) << 4));
+                um1 = udmin * (float)((ub->scales[is + 4] >> 4) | ((ub->scales[is] >> 6) << 4));
+            }
+
+            float gd2, gm2, ud2, um2;
+            if ((is + 1) < 4) {
+                gd2 = gd * (float)(gb->scales[is + 1] & 63);
+                gm2 = gdmin * (float)(gb->scales[is + 1 + 4] & 63);
+                ud2 = ud * (float)(ub->scales[is + 1] & 63);
+                um2 = udmin * (float)(ub->scales[is + 1 + 4] & 63);
+            } else {
+                gd2 = gd * (float)((gb->scales[is + 1 + 4] & 0x0F) | ((gb->scales[is + 1 - 4] >> 6) << 4));
+                gm2 = gdmin * (float)((gb->scales[is + 1 + 4] >> 4) | ((gb->scales[is + 1] >> 6) << 4));
+                ud2 = ud * (float)((ub->scales[is + 1 + 4] & 0x0F) | ((ub->scales[is + 1 - 4] >> 6) << 4));
+                um2 = udmin * (float)((ub->scales[is + 1 + 4] >> 4) | ((ub->scales[is + 1] >> 6) << 4));
+            }
+
+            for (int l = 0; l < 32; l++) {
+                float gw = gd1 * (float)(gb->qs[qs_base + l] & 0xF) - gm1;
+                float uw = ud1 * (float)(ub->qs[qs_base + l] & 0xF) - um1;
+                float xv = x[x_base + l];
+                gate_sum += gw * xv;
+                up_sum += uw * xv;
+            }
+
+            for (int l = 0; l < 32; l++) {
+                float gw = gd2 * (float)(gb->qs[qs_base + l] >> 4) - gm2;
+                float uw = ud2 * (float)(ub->qs[qs_base + l] >> 4) - um2;
+                float xv = x[x_base + 32 + l];
+                gate_sum += gw * xv;
+                up_sum += uw * xv;
+            }
+        }
+    }
+
+    // SIMD reduction across all 32 threads
+    gate_sum = simd_sum(gate_sum);
+    up_sum = simd_sum(up_sum);
+
+    if (tiisg == 0) {
+        float silu = gate_sum / (1.0f + exp(-gate_sum));
+        float activated = silu * up_sum;
+        const int output_idx = batch_idx * n_ff + row_idx;
+        gate_buf[output_idx] = activated;
+    }
+}
+
