+/// Dense Q4_K MVM v2 - OPTIMIZED for 100% thread utilization
+/// When n_in=4096, blocks_per_row=16, but we have 32 threads
+/// v2 uses 2 threads per block: each processes half (128 values)
+kernel void dense_mvm_q4_k_v2(
+    device const uchar *weights_q4 [[buffer(0)]],  // Q4_K weights [m, n] - RESIDENT
+    device const float *input [[buffer(1)]],       // Input vector [n]
+    device float *output [[buffer(2)]],            // Output vector [m]
+    constant uint &n_out [[buffer(3)]],            // Output dimension (m)
+    constant uint &n_in [[buffer(4)]],             // Input dimension (n)
+    uint3 tgpig [[threadgroup_position_in_grid]],  // Threadgroup ID = row index
+    uint tiisg [[thread_index_in_simdgroup]]       // Thread index in SIMD group (0-31)
+) {
+    const int row_idx = tgpig.x;
+    if (row_idx >= n_out) return;
+
+    // Row stride: Q4_K blocks are 144 bytes each, containing 256 values
+    const int blocks_per_row = (n_in + 255) / 256;
+    const int row_stride_bytes = blocks_per_row * 144;
+
+    device const block_q4_K *row_blocks = (device const block_q4_K *)(weights_q4 + row_idx * row_stride_bytes);
+
+    float sum = 0.0f;
+
+    // v2: 32 threads process 16 blocks (2 threads per block)
+    // Thread tiisg processes: block = tiisg/2, half_idx = tiisg % 2
+    // half_idx 0: chunks 0,1 (values 0-127), half_idx 1: chunks 2,3 (values 128-255)
+    const int block_idx = tiisg / 2;
+    const int half_idx = tiisg & 1;
+
+    if (block_idx < blocks_per_row) {
+        device const block_q4_K *b = row_blocks + block_idx;
+
+        const float d = (float)b->d;
+        const float dmin = (float)b->dmin;
+        const int input_base = block_idx * 256 + half_idx * 128;
+
+        // Process 2 chunks (128 values) - half_idx 0 does chunks 0,1; half_idx 1 does chunks 2,3
+        for (int chunk_offset = 0; chunk_offset < 2; chunk_offset++) {
+            const int chunk = half_idx * 2 + chunk_offset;
+            const int is = chunk * 2;
+            const int qs_base = chunk * 32;
+            const int x_base = input_base + chunk_offset * 64;
+
+            // Get scales for lower nibbles (sub-block is)
+            float iscale0, imin0;
+            if (is < 4) {
+                iscale0 = (float)(b->scales[is] & 63);
+                imin0   = (float)(b->scales[is + 4] & 63);
+            } else {
+                iscale0 = (float)((b->scales[is + 4] & 0x0F) | ((b->scales[is - 4] >> 6) << 4));
+                imin0   = (float)((b->scales[is + 4] >> 4)   | ((b->scales[is]     >> 6) << 4));
+            }
+            const float d1 = d * iscale0;
+            const float m1 = dmin * imin0;
+
+            // Get scales for upper nibbles (sub-block is+1)
+            float iscale1, imin1;
+            if ((is + 1) < 4) {
+                iscale1 = (float)(b->scales[is + 1] & 63);
+                imin1   = (float)(b->scales[is + 1 + 4] & 63);
+            } else {
+                iscale1 = (float)((b->scales[is + 1 + 4] & 0x0F) | ((b->scales[is + 1 - 4] >> 6) << 4));
+                imin1   = (float)((b->scales[is + 1 + 4] >> 4)   | ((b->scales[is + 1]     >> 6) << 4));
+            }
+            const float d2 = d * iscale1;
+            const float m2 = dmin * imin1;
+
+            // Process 32 bytes = 64 values
+            for (int j = 0; j < 32; j++) {
+                uchar qbyte = b->qs[qs_base + j];
+
+                // Lower nibble
+                float w0 = d1 * (float)(qbyte & 0xF) - m1;
+                sum += w0 * input[x_base + j];
+
+                // Upper nibble
+                float w1 = d2 * (float)(qbyte >> 4) - m2;
+                sum += w1 * input[x_base + 32 + j];
+            }
+        }
+    }
+
+    // SIMD reduction: all 32 threads contribute
+    sum = simd_sum(sum);
+
+    // Only first thread writes result
+    if (tiisg == 0) {
+        output[row_idx] = sum;
+    }
+}
